func newNovelCashbackOptimizeCmd(flags *rootFlags) *cobra.Command {
	var flagTier string
	var flagReward string
	var flagPreferRestock bool
	var flagMaxExtra string

	cmd := &cobra.Command{
		Use:     "optimize",
		Short:   "Computes the cheapest set of items to add (or whether to wait) to cross the next cashback tier",
		Example: "  shopper-pp-cli cashback optimize --tier 2399 --reward 100 --json",
		Long: `Reads your current cart total from /cart/summary. Given a --tier target (R$ value),
computes the gap and suggests the cheapest catalog items that close it.

  --tier         Target R$ total to reach (e.g. 2399). Required.
  --reward       Description of the reward at that tier (e.g. "R$50 cashback").
  --prefer-restock  Prefer items flagged by restock-predict as needing restocking.
  --max-extra    Maximum extra spend beyond the gap (default: tier * 10%).

If your cart is already at or above the tier, reports "already_above_tier".

NOTE: /catalog/search is used to find cheap fill-up items. Items are selected
greedily by price (cheapest first) until the gap is closed without exceeding max-extra.`,
		Annotations: map[string]string{
			"mcp:read-only":          "true",
			"pp:no-error-path-probe": "true",
		},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), `{"dry_run":true,"would":"fetch /cart/summary and /catalog/search to compute cashback optimization"}`)
				return nil
			}

			// Parse --tier
			tierVal, err := parseCurrency(flagTier)
			if err != nil || tierVal <= 0 {
				return usageErr(fmt.Errorf("--tier is required and must be a positive number (e.g. --tier 2399)"))
			}

			// Parse --max-extra
			var maxExtra float64
			if flagMaxExtra != "" {
				maxExtra, err = parseCurrency(flagMaxExtra)
				if err != nil {
					return usageErr(fmt.Errorf("invalid --max-extra %q: must be a number", flagMaxExtra))
				}
			} else {
				maxExtra = tierVal * 0.10 // default: 10% of tier
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}

			// Fetch cart total
			cartData, err := c.Get(cmd.Context(), "/cart/summary", nil)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			currentTotal := extractCartTotal(cartData)

			result := cashbackOptimizeResult{
				CurrentTotal:  math.Round(currentTotal*100) / 100,
				Tier:          tierVal,
				Gap:           math.Round(math.Max(0, tierVal-currentTotal)*100) / 100,
				Reward:        flagReward,
				SuggestedAdds: make([]cashbackSuggestedItem, 0),
				MaxExtra:      maxExtra,
			}

			if currentTotal >= tierVal {
				result.Status = "already_above_tier"
				result.Note = fmt.Sprintf("Your current cart total (R$%.2f) already meets or exceeds the tier (R$%.2f).", currentTotal, tierVal)
				result.ProjectedTotal = currentTotal
				return printJSONFiltered(cmd.OutOrStdout(), result, flags)
			}

			gap := tierVal - currentTotal

			// Optionally get restock predictions to prefer those items
			restockIDs := make(map[string]bool)
			if flagPreferRestock {
				db, derr := store.OpenWithContext(cmd.Context(), defaultDBPath("shopper-pp-cli"))
				if derr == nil {
					defer db.Close()
					snaps, serr := store.LatestCartSnapshots(db.DB(), 10)
					if serr == nil && len(snaps) >= 2 {
						// Use product IDs from the earliest snapshot that aren't in the latest
						latestIDs := make(map[string]bool)
						for _, item := range snaps[0].Items {
							latestIDs[item.ID] = true
						}
						for _, item := range snaps[len(snaps)-1].Items {
							if !latestIDs[item.ID] {
								restockIDs[item.ID] = true
							}
						}
					}
				}
			}

			// Fetch catalog items to fill the gap
			var catalogItems []cashbackSuggestedItem
			searchData, _, serr := c.PostQueryWithParams(cmd.Context(), "/catalog/search", nil,
				map[string]any{"query": "", "page": 0, "size": 100})
			if serr == nil && searchData != nil {
				catalogItems = extractCatalogItemsForCashback(searchData, restockIDs)
			}

			// Sort: restock items first, then by price ascending
			sort.Slice(catalogItems, func(i, j int) bool {
				if catalogItems[i].IsRestock != catalogItems[j].IsRestock {
					return catalogItems[i].IsRestock
				}
				return catalogItems[i].Price < catalogItems[j].Price
			})

			// Greedy selection: pick cheapest items until gap + maxExtra is covered
			maxSpend := gap + maxExtra
			accumulated := 0.0
			for _, item := range catalogItems {
				if item.Price <= 0 {
					continue
				}
				if accumulated >= gap {
					break
				}
				if accumulated+item.Price > maxSpend {
					continue
				}
				result.SuggestedAdds = append(result.SuggestedAdds, item)
				accumulated += item.Price
			}

			result.ProjectedTotal = math.Round((currentTotal+accumulated)*100) / 100
			if len(result.SuggestedAdds) == 0 {
				result.Status = "no_suggestions"
				result.Note = fmt.Sprintf("Gap is R$%.2f but no suitable items found in catalog within R$%.2f budget. Try a larger --max-extra.", gap, maxExtra)
			} else if accumulated < gap {
				result.Status = "partial"
				result.Note = fmt.Sprintf("Could only find R$%.2f of the R$%.2f gap within the R$%.2f max-extra budget.", math.Round(accumulated*100)/100, math.Round(gap*100)/100, maxExtra)
			} else {
				result.Status = "optimized"
			}

			return printJSONFiltered(cmd.OutOrStdout(), result, flags)
		},
	}
	cmd.Flags().StringVar(&flagTier, "tier", "", "Target cashback tier total in R$ (e.g. 2399). Required.")
	cmd.Flags().StringVar(&flagReward, "reward", "", "Description of reward at the tier (e.g. 'R$50 cashback')")
	cmd.Flags().BoolVar(&flagPreferRestock, "prefer-restock", false, "Prefer items that restock-predict flags as needed")
	cmd.Flags().StringVar(&flagMaxExtra, "max-extra", "", "Maximum extra spend beyond the gap (default: 10%% of tier)")
	return cmd
}

// parseCurrency parses a string like "2399", "2399.00", "R$2399" into a float64.
func parseCurrency(s string) (float64, error) {
	s = strings.TrimSpace(s)
	s = strings.TrimPrefix(s, "R$")
	s = strings.TrimPrefix(s, "r$")
	s = strings.ReplaceAll(s, ",", ".")
	return strconv.ParseFloat(strings.TrimSpace(s), 64)
}

// extractCartTotal extracts the total amount from /cart/summary response.
func extractCartTotal(data json.RawMessage) float64 {
	var top map[string]any
	if json.Unmarshal(data, &top) != nil {
		return 0
	}
	// Try common total field names
	for _, key := range []string{"total", "totalValue", "total_value", "subtotal", "amount", "valor_total"} {
		if v, ok := top[key]; ok {
			if f, ok := v.(float64); ok {
				return f
			}
		}
	}
	// Try nested summary object
	for _, key := range []string{"summary", "totals", "pricing"} {
		if v, ok := top[key]; ok {
			if m, ok := v.(map[string]any); ok {
				for _, innerKey := range []string{"total", "totalValue", "amount"} {
					if f, ok := m[innerKey].(float64); ok {
						return f
					}
				}
			}
		}
	}
	return 0
}

// extractCatalogItemsForCashback extracts product IDs, names, and prices from a search response.
func extractCatalogItemsForCashback(data json.RawMessage, restockIDs map[string]bool) []cashbackSuggestedItem {
	var top map[string]json.RawMessage
	if json.Unmarshal(data, &top) != nil {
		return nil
	}
	var rawItems []json.RawMessage
	for _, key := range []string{"items", "data", "products", "results"} {
		if raw, ok := top[key]; ok {
			if json.Unmarshal(raw, &rawItems) == nil && len(rawItems) > 0 {
				break
			}
		}
	}
	out := make([]cashbackSuggestedItem, 0, len(rawItems))
	for _, raw := range rawItems {
		var obj map[string]any
		if json.Unmarshal(raw, &obj) != nil {
			continue
		}
		id := extractAnyString(obj, "id", "productId", "product_id")
		name := extractAnyString(obj, "name", "title")
		price := extractAnyFloat(obj, "price", "unit_price", "preco")
		if id == "" || price <= 0 {
			continue
		}
		out = append(out, cashbackSuggestedItem{
			ID:        id,
			Name:      name,
			Price:     math.Round(price*100) / 100,
			IsRestock: restockIDs[id],
		})
	}
	return out
}
